sql_examples.sql:
-- OS 인증으로 SYSDBA 접속
sqlplus / as sysdba

-- 인스턴스 기동
STARTUP;

-- 또는 MOUNT 상태까지만 기동
STARTUP MOUNT;

-- MOUNT에서 OPEN으로 전환
ALTER DATABASE OPEN;

-- 가장 일반적인 종료 (미커밋 롤백 후 종료)
SHUTDOWN IMMEDIATE;

-- 현재 트랜잭션 완료 후 종료
SHUTDOWN TRANSACTIONAL;

-- 모든 세션 종료 대기 후 종료
SHUTDOWN NORMAL;

-- 강제 종료 (다음 기동 시 인스턴스 복구 필요)
SHUTDOWN ABORT;

-- 출력 포맷 설정
SET LINESIZE 200
SET PAGESIZE 50
SET SERVEROUTPUT ON

-- 현재 컨테이너 확인
SHOW CON_NAME;

-- PDB 목록 확인
SHOW PDBS;

-- PDB로 전환
ALTER SESSION SET CONTAINER = pdb1;

-- PDB에서 작업 수행
SELECT name, open_mode FROM v$pdbs;

-- CDB$ROOT로 복귀
ALTER SESSION SET CONTAINER = CDB$ROOT;

-- 특정 파라미터 조회
SHOW PARAMETER db_name;
SHOW PARAMETER sga;
SHOW PARAMETER pga;

-- SGA 정보 조회
SHOW SGA;

-- V$PARAMETER로 세부 파라미터 조회
SELECT name, value, isdefault, ismodified
FROM v$parameter
WHERE name LIKE '%memory%'
ORDER BY name;

-- EM Express HTTPS 포트 설정
EXEC DBMS_XDB_CONFIG.setHTTPSPort(5500);

-- 현재 설정된 포트 확인
SELECT DBMS_XDB_CONFIG.getHTTPSPort() AS https_port FROM dual;

-- PDB에서 EM Express 활성화 (PDB별 별도 포트)
ALTER SESSION SET CONTAINER = pdb1;
EXEC DBMS_XDB_CONFIG.setHTTPSPort(5501);

-- RMAN으로 로컬 접속
rman target /

-- RMAN에서 데이터베이스 기동
RMAN> STARTUP MOUNT;

-- RMAN에서 데이터베이스 오픈
RMAN> SQL 'ALTER DATABASE OPEN';

-- 전체 데이터베이스 백업
RMAN> BACKUP DATABASE PLUS ARCHIVELOG;

-- 증분 Level 0 백업 (전체 기준)
RMAN> BACKUP INCREMENTAL LEVEL 0 DATABASE;

-- 증분 Level 1 백업 (변경분만)
RMAN> BACKUP INCREMENTAL LEVEL 1 DATABASE;

-- 특정 테이블스페이스 백업
RMAN> BACKUP TABLESPACE users;

-- 아카이브 로그 백업
RMAN> BACKUP ARCHIVELOG ALL DELETE ALL INPUT;

-- 백업 목록 조회
RMAN> LIST BACKUP SUMMARY;

-- 데이터 파일 검증
RMAN> VALIDATE DATABASE;

-- 복구 가능성 검증
RMAN> RESTORE DATABASE PREVIEW;

-- 불필요한 백업 정리 (보존 정책 기반)
RMAN> DELETE OBSOLETE;

-- 백업 보존 정책 설정
RMAN> CONFIGURE RETENTION POLICY TO REDUNDANCY 2;
